50: absl::StatusOr<HealthCheckerSharedPtr>
51: HealthCheckerFactory::create(const envoy::config::core::v3::HealthCheck& health_check_config,
52:                              Upstream::Cluster& cluster,
53:                              Server::Configuration::ServerFactoryContext& server_context) {
54:   Server::Configuration::CustomHealthCheckerFactory* factory = nullptr;
55: 
56:   switch (health_check_config.health_checker_case()) {
57:   case envoy::config::core::v3::HealthCheck::HealthCheckerCase::HEALTH_CHECKER_NOT_SET:
58:     return absl::InvalidArgumentError("invalid cluster config");
59:   case envoy::config::core::v3::HealthCheck::HealthCheckerCase::kHttpHealthCheck:
60:     factory = &Config::Utility::getAndCheckFactoryByName<
61:         Server::Configuration::CustomHealthCheckerFactory>("envoy.health_checkers.http");
62:     break;
63:   case envoy::config::core::v3::HealthCheck::HealthCheckerCase::kTcpHealthCheck:
64:     factory = &Config::Utility::getAndCheckFactoryByName<
65:         Server::Configuration::CustomHealthCheckerFactory>("envoy.health_checkers.tcp");
66:     break;
67:   case envoy::config::core::v3::HealthCheck::HealthCheckerCase::kGrpcHealthCheck:
68:     if (!(cluster.info()->features() & Upstream::ClusterInfo::Features::HTTP2)) {
69:       return absl::InvalidArgumentError(fmt::format(
70:           "{} cluster must support HTTP/2 for gRPC healthchecking", cluster.info()->name()));
71:     }
72:     factory = &Config::Utility::getAndCheckFactoryByName<
73:         Server::Configuration::CustomHealthCheckerFactory>("envoy.health_checkers.grpc");
74:     break;
75:   case envoy::config::core::v3::HealthCheck::HealthCheckerCase::kCustomHealthCheck: {
76:     factory =
77:         &Config::Utility::getAndCheckFactory<Server::Configuration::CustomHealthCheckerFactory>(
78:             health_check_config.custom_health_check());
79:   }
80:   }
81: 
82:   std::unique_ptr<Server::Configuration::HealthCheckerFactoryContext> context(
83:       new HealthCheckerFactoryContextImpl(cluster, server_context));
84: 
85:   if (!health_check_config.event_log_path().empty() /* deprecated */ ||
86:       !health_check_config.event_logger().empty()) {
87:     HealthCheckEventLoggerPtr event_logger;
88:     event_logger = std::make_unique<HealthCheckEventLoggerImpl>(health_check_config, *context);
89:     context->setEventLogger(std::move(event_logger));
90:   }
91:   return factory->createCustomHealthChecker(health_check_config, *context);
92: }
